INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('iceland', 'Iceland', 'Iceland', 'Land of fire and ice — volcanic landscapes, glaciers, waterfalls, and endless horizons from the drone.', 'Land of fire and ice — volcanic landscapes, glaciers, waterfalls, and endless horizons from the drone.', 64.75, -17.84, 'Europe', 2019);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('canadian-rockies', 'Canadian Rockies', 'Canadian Rockies', 'Turquoise lakes, towering peaks, and pristine wilderness across British Columbia and Alberta.', 'Turquoise lakes, towering peaks, and pristine wilderness across British Columbia and Alberta.', 52.24, -118.62, 'North America', 2019);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('malaysia', 'Malaysia', 'Malaysia', 'Tropical beaches, Kuala Lumpur skyline, and lush jungles of Southeast Asia.', 'Tropical beaches, Kuala Lumpur skyline, and lush jungles of Southeast Asia.', 4.31, 100.99, 'Asia', 2020);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('bali', 'Bali', 'Bali', 'Rice terraces, temple ceremonies, dramatic cliffs, and endless sunsets over the Indian Ocean.', 'Rice terraces, temple ceremonies, dramatic cliffs, and endless sunsets over the Indian Ocean.', -8.47, 115.27, 'Asia', 2022);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('yosemite', 'Yosemite', 'Yosemite', 'Granite cliffs, giant sequoias, and the breathtaking valley views of California''s crown jewel.', 'Granite cliffs, giant sequoias, and the breathtaking valley views of California''s crown jewel.', 37.77, -119.81, 'North America', 2022);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('silicon-valley', 'Silicon Valley', 'Silicon Valley', 'The tech capital of the world — aerial views over San Jose and the Bay Area.', 'The tech capital of the world — aerial views over San Jose and the Bay Area.', 37.34, -122.01, 'North America', 2022);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('mexican-caribbean', 'Mexican Caribbean', 'Mexican Caribbean', 'Turquoise waters, ancient Mayan ruins, cenotes, and white sand beaches along the Riviera Maya.', 'Turquoise waters, ancient Mayan ruins, cenotes, and white sand beaches along the Riviera Maya.', 20.8, -87.19, 'North America', 2023);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('yucatan', 'Yucatán', 'Yucatán', 'Pink flamingo lagoons, Mayan pyramids, and colorful colonial towns deep in the Mexican interior.', 'Pink flamingo lagoons, Mayan pyramids, and colorful colonial towns deep in the Mexican interior.', 20.58, -89.35, 'North America', 2023);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('guatemala', 'Guatemala', 'Guatemala', 'Volcanoes, misty highlands, Lake Atitlán, and the ancient ruins of Tikal from above.', 'Volcanoes, misty highlands, Lake Atitlán, and the ancient ruins of Tikal from above.', 14.99, -90.21, 'North America', 2023);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('ecuador', 'Ecuador', 'Ecuador', 'The equator line, Andean highlands, cloud forests, and the diversity of a tiny, mighty country.', 'The equator line, Andean highlands, cloud forests, and the diversity of a tiny, mighty country.', -0.25, -78.38, 'South America', 2024);
INSERT INTO destinations (id, name_en, name_cs, description_en, description_cs, lat, lng, continent, visited_at_year) VALUES ('colombia', 'Colombia', 'Colombia', 'Caribbean coastline, colonial Cartagena, lush coffee country, and vibrant cities from the sky.', 'Caribbean coastline, colonial Cartagena, lush coffee country, and vibrant cities from the sky.', 8.73, -74.55, 'South America', 2024);
